import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const CLASS_META = {
  MID: { badge: 'badge-amber', label: 'Mild dementia'      },
  MOD: { badge: 'badge-red',   label: 'Moderate dementia'  },
  NOD: { badge: 'badge-teal',  label: 'No dementia'        },
  VMD: { badge: 'badge-blue',  label: 'Very mild dementia' },
};

export default function HistoryPage({ history, setResult }) {
  const navigate = useNavigate();
  const [query, setQuery] = useState('');

  const filtered = history.filter(r =>
    r.subjectId?.toLowerCase().includes(query.toLowerCase()) ||
    r.topClass?.toLowerCase().includes(query.toLowerCase())
  );

  function viewResult(r) {
    setResult(r);
    navigate('/results');
  }

  return (
    <div style={{ maxWidth: 1100, margin: '0 auto', padding: '28px 24px 48px' }}>

      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24, flexWrap: 'wrap', gap: 12 }}>
        <div>
          <h1 style={{ fontSize: 20, fontWeight: 600, color: '#24292F', marginBottom: 4 }}>
            Analysis history
          </h1>
          <p style={{ fontSize: 13, color: '#57606A' }}>
            {history.length} total scan{history.length !== 1 ? 's' : ''} analysed
          </p>
        </div>
        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
          <input
            type="search"
            placeholder="Search subject ID or stage…"
            value={query}
            onChange={e => setQuery(e.target.value)}
            style={{
              padding: '7px 12px', border: '1px solid #D0D7DE', borderRadius: 6,
              fontSize: 13, width: 220, outline: 'none',
            }}
          />
          <button className="btn btn-primary btn-sm" onClick={() => navigate('/upload')}>
            + New scan
          </button>
        </div>
      </div>

      {/* Table */}
      {filtered.length === 0 ? (
        <EmptyState query={query} onNew={() => navigate('/upload')} />
      ) : (
        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: '#F6F8FA', borderBottom: '1px solid #E1E4E8' }}>
                {['Subject', 'Date', 'Stage', 'Probability', 'Confidence', ''].map(h => (
                  <th key={h} style={{
                    padding: '10px 16px', textAlign: 'left',
                    fontSize: 11, fontFamily: 'var(--mono)',
                    fontWeight: 500, color: '#57606A',
                    textTransform: 'uppercase', letterSpacing: '.06em',
                    whiteSpace: 'nowrap',
                  }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((r, i) => {
                const meta = CLASS_META[r.topClass] || CLASS_META.MID;
                return (
                  <tr
                    key={r.id || i}
                    onClick={() => viewResult(r)}
                    style={{
                      borderBottom: '1px solid #F0F2F4',
                      cursor: 'pointer',
                      transition: 'background .12s',
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = '#F6F8FA'}
                    onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
                  >
                    <td style={{ padding: '14px 16px' }}>
                      <div style={{ fontFamily: 'var(--mono)', fontSize: 13, fontWeight: 500, color: '#24292F' }}>
                        {r.subjectId}
                      </div>
                      <div style={{ fontSize: 11, color: '#8B949E', marginTop: 2 }}>
                        {r.id}
                      </div>
                    </td>
                    <td style={{ padding: '14px 16px', fontSize: 13, color: '#57606A', whiteSpace: 'nowrap' }}>
                      {r.date}
                    </td>
                    <td style={{ padding: '14px 16px' }}>
                      <span className={`badge ${meta.badge}`}>
                        {r.topClass} · {meta.label}
                      </span>
                    </td>
                    <td style={{ padding: '14px 16px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                        <div style={{ width: 60, height: 4, background: '#EFF1F3', borderRadius: 99, overflow: 'hidden' }}>
                          <div style={{
                            width: `${r.topProb * 100}%`, height: '100%', borderRadius: 99,
                            background: r.topProb > 0.75 ? '#0E7F6F' : r.topProb > 0.5 ? '#F0A500' : '#F85149',
                          }} />
                        </div>
                        <span style={{ fontFamily: 'var(--mono)', fontSize: 12, color: '#57606A' }}>
                          {Math.round(r.topProb * 100)}%
                        </span>
                      </div>
                    </td>
                    <td style={{ padding: '14px 16px' }}>
                      <span className={`badge ${r.confidence === 'High' ? 'badge-teal' : 'badge-amber'}`}>
                        {r.confidence}
                      </span>
                    </td>
                    <td style={{ padding: '14px 16px', textAlign: 'right' }}>
                      <button
                        className="btn btn-sm"
                        onClick={e => { e.stopPropagation(); viewResult(r); }}
                      >
                        View →
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function EmptyState({ query, onNew }) {
  return (
    <div style={{
      textAlign: 'center', padding: '64px 24px',
      border: '1px dashed #D0D7DE', borderRadius: 12,
      background: '#FAFBFC',
    }}>
      <div style={{ fontSize: 36, marginBottom: 12 }}>🧠</div>
      <div style={{ fontSize: 16, fontWeight: 600, color: '#24292F', marginBottom: 6 }}>
        {query ? `No results for "${query}"` : 'No analyses yet'}
      </div>
      <div style={{ fontSize: 13, color: '#57606A', marginBottom: 20 }}>
        {query ? 'Try a different subject ID or stage name.' : 'Upload your first scan to get started.'}
      </div>
      {!query && (
        <button className="btn btn-primary" onClick={onNew}>
          Upload a scan
        </button>
      )}
    </div>
  );
}
